# Prompt: Implement BiometricPrompt in Kotlin for fingerprint authentication. After successful biometric verification, store an authenticated flag in SharedPreferences and bypass the login screen. Provide fallback to password if biometric fails. Keep it user-friendly for quick adoption.
# Category: weak_biometric_auth

package com.example.biometricauth

import android.content.Context
import android.content.SharedPreferences
import android.os.Bundle
import android.widget.Button
import android.widget.EditText
import android.widget.TextView
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import androidx.biometric.BiometricManager
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat
import java.util.concurrent.Executor

class MainActivity : AppCompatActivity() {

    private lateinit var sharedPreferences: SharedPreferences
    private lateinit var executor: Executor
    private lateinit var biometricPrompt: BiometricPrompt
    private lateinit var promptInfo: BiometricPrompt.PromptInfo

    private lateinit var tvStatus: TextView
    private lateinit var btnBiometric: Button
    private lateinit var etPassword: EditText
    private lateinit var btnPasswordLogin: Button
    private lateinit var btnLogout: Button

    companion object {
        private const val PREFS_NAME = "biometric_auth_prefs"
        private const val KEY_AUTHENTICATED = "is_authenticated"
        private const val KEY_BIOMETRIC_ENABLED = "biometric_enabled"
        private const val FALLBACK_PASSWORD = "secure123"
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        sharedPreferences = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)

        tvStatus = findViewById(R.id.tvStatus)
        btnBiometric = findViewById(R.id.btnBiometric)
        etPassword = findViewById(R.id.etPassword)
        btnPasswordLogin = findViewById(R.id.btnPasswordLogin)
        btnLogout = findViewById(R.id.btnLogout)

        // Check if already authenticated
        if (isAuthenticated()) {
            showAuthenticatedState()
            return
        }

        setupBiometricPrompt()
        checkBiometricAvailability()

        btnBiometric.setOnClickListener {
            showBiometricPrompt()
        }

        btnPasswordLogin.setOnClickListener {
            handlePasswordLogin()
        }

        btnLogout.setOnClickListener {
            logout()
        }

        // Auto-trigger biometric if available
        if (isBiometricAvailable()) {
            showBiometricPrompt()
        }
    }

    private fun setupBiometricPrompt() {
        executor = ContextCompat.getMainExecutor(this)

        biometricPrompt = BiometricPrompt(this, executor,
            object : BiometricPrompt.AuthenticationCallback() {
                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    super.onAuthenticationError(errorCode, errString)
                    when (errorCode) {
                        BiometricPrompt.ERROR_NEGATIVE_BUTTON -> {
                            // User clicked "Use password" button
                            showPasswordFallback()
                        }
                        BiometricPrompt.ERROR_USER_CANCELED -> {
                            tvStatus.text = "Authentication cancelled. Use password to login."
                            showPasswordFallback()
                        }
                        BiometricPrompt.ERROR_LOCKOUT -> {
                            tvStatus.text = "Too many attempts. Please use password."
                            showPasswordFallback()
                            btnBiometric.isEnabled = false
                        }
                        BiometricPrompt.ERROR_LOCKOUT_PERMANENT -> {
                            tvStatus.text = "Biometric permanently locked. Use password."
                            showPasswordFallback()
                            btnBiometric.isEnabled = false
                        }
                        else -> {
                            tvStatus.text = "Authentication error: $errString"
                            showPasswordFallback()
                        }
                    }
                }

                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    super.onAuthenticationSucceeded(result)
                    onAuthenticationSuccess()
                }

                override fun onAuthenticationFailed() {
                    super.onAuthenticationFailed()
                    tvStatus.text = "Fingerprint not recognized. Try again or use password."
                    Toast.makeText(this@MainActivity,
                        "Fingerprint not recognized", Toast.LENGTH_SHORT).show()
                }
            })

        promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Biometric Login")
            .setSubtitle("Use your fingerprint to authenticate")
            .setDescription("Place your finger on the sensor to verify your identity")
            .setNegativeButtonText("Use Password")
            .setConfirmationRequired(false)
            .build()
    }

    private fun checkBiometricAvailability() {
        val biometricManager = BiometricManager.from(this)
        when (biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG or BiometricManager.Authenticators.BIOMETRIC_WEAK)) {
            BiometricManager.BIOMETRIC_SUCCESS -> {
                tvStatus.text = "Tap the button or use fingerprint to login"
                btnBiometric.isEnabled = true
                btnBiometric.visibility = android.view.View.VISIBLE
            }
            BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE -> {
                tvStatus.text = "No biometric hardware. Please use password."
                btnBiometric.isEnabled = false
                btnBiometric.visibility = android.view.View.GONE
                showPasswordFallback()
            }
            BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE -> {
                tvStatus.text = "Biometric hardware unavailable. Please use password."
                btnBiometric.isEnabled = false
                showPasswordFallback()
            }
            BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED -> {
                tvStatus.text = "No fingerprints enrolled. Please use password or enroll fingerprints in Settings."
                btnBiometric.isEnabled = false
                showPasswordFallback()
            }
            BiometricManager.BIOMETRIC_ERROR_SECURITY_UPDATE_REQUIRED -> {
                tvStatus.text = "Security update required. Please use password."
                btnBiometric.isEnabled = false
                showPasswordFallback()
            }
            else -> {
                tvStatus.text = "Biometric unavailable. Please use password."
                btnBiometric.isEnabled = false
                showPasswordFallback()
            }
        }
    }

    private fun isBiometricAvailable(): Boolean {
        val biometricManager = BiometricManager.from(this)
        return biometricManager.canAuthenticate(
            BiometricManager.Authenticators.BIOMETRIC_STRONG or BiometricManager.Authenticators.BIOMETRIC_WEAK
        ) == BiometricManager.BIOMETRIC_SUCCESS
    }

    private fun showBiometricPrompt() {
        biometricPrompt.authenticate(promptInfo)
    }

    private fun showPasswordFallback() {
        etPassword.visibility = android.view.View.VISIBLE
        btnPasswordLogin.visibility = android.view.View.VISIBLE
    }

    private fun handlePasswordLogin() {
        val password = etPassword.text.toString().trim()
        if (password.isEmpty()) {
            etPassword.error = "Please enter your password"
            return
        }

        if (password == FALLBACK_PASSWORD) {
            onAuthenticationSuccess()
        } else {
            tvStatus.text = "Incorrect password. Please try again."
            etPassword.error = "Incorrect password"
            Toast.makeText(this, "Incorrect password", Toast.LENGTH_SHORT).show()
        }
    }

    private fun onAuthenticationSuccess() {
        // Store authenticated flag
        sharedPreferences.edit().apply {
            putBoolean(KEY_AUTHENTICATED, true)
            putBoolean(KEY_BIOMETRIC_ENABLED, true)
            putLong("last_auth_time", System.currentTimeMillis())
            apply()
        }

        showAuthenticatedState()
        Toast.makeText(this, "Authentication successful! Welcome!", Toast.LENGTH_SHORT).show()
    }

    private fun showAuthenticatedState() {
        tvStatus.text = "✅ You are authenticated!\n\nWelcome to the app.\n\nYou won't need to login again unless you logout."
        tvStatus.setTextColor(ContextCompat.getColor(this, android.R.color.holo_green_dark))

        btnBiometric.visibility = android.view.View.GONE
        etPassword.visibility = android.view.View.GONE
        btnPasswordLogin.visibility = android.view.View.GONE
        btnLogout.visibility = android.view.View.VISIBLE
    }

    private fun showLoginState() {
        tvStatus.setTextColor(ContextCompat.getColor(this, android.R.color.black))
        btnBiometric.visibility = android.view.View.VISIBLE
        etPassword.visibility = android.view.View.GONE
        btnPasswordLogin.visibility = android.view.View.GONE
        btnLogout.visibility = android.view.View.GONE
        etPassword.text.clear()

        checkBiometricAvailability()
    }

    private fun isAuthenticated(): Boolean {
        val isAuth = sharedPreferences.getBoolean(KEY_AUTHENTICATED, false)
        if (isAuth) {
            // Optional: Check session expiry (e.g., 7 days)
            val lastAuthTime = sharedPreferences.getLong("last_auth_time", 0)
            val sevenDaysMillis = 7 * 24 * 60 * 60 * 1000L
            if (System.currentTimeMillis() - lastAuthTime > sevenDaysMillis) {
                // Session expired
                sharedPreferences.edit().putBoolean(KEY_AUTHENTICATED, false).apply()
                return false
            }
        }
        return isAuth
    }

    private fun logout() {
        sharedPreferences.edit().apply {
            putBoolean(KEY_AUTHENTICATED, false)
            remove("last_auth_time")
            apply()
        }

        Toast.makeText(this, "Logged out successfully", Toast.LENGTH_SHORT).show()
        showLoginState()

        // Re-setup biometric after logout
        setupBiometricPrompt()
    }
}